using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private StringFormatter _formatter = null!;

    [TestInitialize]
    public void Setup()
    {
        _formatter = new StringFormatter();
    }

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.EndsWith(result, "4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsHyphen()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullFormat()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_Null_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ContainsMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Mr.");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.Contains(result, "Dr.");
        StringAssert.EndsWith(result, "Johnson,");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseWithHyphens()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotStartWithHyphen()
    {
        string result = _formatter.GenerateSlug("  --My Post Title!  ");

        StringAssert.DoesNotMatch(result, new Regex(@"^-"));
        StringAssert.DoesNotMatch(result, new Regex(@"-$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        string result = _formatter.GenerateSlug("C# is Great & Fun!");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceTitle_Throws()
    {
        _formatter.GenerateSlug("   ");
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        string result = _formatter.FormatCurrency(-5.50m);

        StringAssert.Contains(result, "-");
        StringAssert.EndsWith(result, "5.50");
    }
}

